sql:
SELECT COUNT(*) AS good_readings_count
FROM weather_readings
WHERE data_quality_flag = 'good';

external_knowledge:
; Temperature-related data quality issues: refer to problems with temperature readings, such as missing data, incorrect units, or inconsistent values; 
; Resolved issues: issues that have been investigated, corrected, or addressed by the maintenance team; 
; Average temperature calculation: the average of all temperature readings associated with the resolved issues for each station.

sql:
SELECT sunHour, sunrise_time
FROM sun_readings
WHERE sun_id = 1;

SELECT AVG(reading_value) AS average_reading
FROM weather_readings
WHERE station_id = 1 AND reading_date = '2023-10-01';

SELECT reading_date
FROM weather_readings
WHERE data_quality_flag = 'good';

SELECT station_name, last_maintenance_date
FROM weather_stations
ORDER BY last_maintenance_date DESC;

SELECT MAX(reading_value) AS max_reading
FROM weather_readings
WHERE station_id = 0;

SELECT maxtempC 
FROM temperature_readings 
WHERE temp_id = 1;

SELECT station_name, location
FROM weather_stations
ORDER BY station_name ASC;
